export function requireWorkspaceMember(role?: WorkspaceRole) {
  return async (req: AuthRequest, res: Response, next: NextFunction) => {
    const workspaceId = extractWorkspaceId(req);
    const membership = await prisma.workspaceMember.findUnique({
      where: { userId_workspaceId: { userId: req.userId!, workspaceId } },
    });
    if (!membership) {
      return res.status(403).json({ error: 'No eres miembro de este workspace' });
    }
    if (role && membership.role !== role && membership.role !== 'OWNER') {
      return res.status(403).json({ error: 'Permisos insuficientes' });
    }
    req.membership = membership;
    next();
  };
}
